import React from "react";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  return (
    <div style={styles.container}>

      <Navbar />

      <div style={styles.main}>

        {/* Doctor Card */}
        <div style={styles.card}>

          {/* Left Section - Image */}
          <div style={styles.left}>
            <img
              src="https://cdn-icons-png.flaticon.com/512/387/387561.png"
              alt="doctor"
              style={styles.image}
            />
          </div>

          {/* Right Section - Details */}
          <div style={styles.right}>
            <h2>Dr. John Smith</h2>
            <p><strong>Specialization:</strong> Cardiologist</p>
            <p><strong>Experience:</strong> 10+ Years</p>
            <p><strong>Qualification:</strong> MBBS, MD</p>

            <p style={styles.about}>
              <strong>About:</strong> Experienced cardiologist with a strong
              background in treating heart-related conditions and patient care.
            </p>

            {/* Appointment Section */}
            <div style={styles.bookingSection}>

              <label>Select Date:</label>
              <input type="date" style={styles.input} />

              <label>Select Time:</label>
              <select style={styles.input}>
                <option>10:00 AM</option>
                <option>11:00 AM</option>
                <option>02:00 PM</option>
                <option>04:00 PM</option>
              </select>

              <button style={styles.button}>
                Book Appointment
              </button>

            </div>
          </div>

        </div>

      </div>

      <Footer />

    </div>
  );
}

export default Doctorprofile;

const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    minHeight: "100vh",
    backgroundColor: "#f4f6f9",
    fontFamily: "Arial, sans-serif",
  },

  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px",
  },

  card: {
    display: "flex",
    backgroundColor: "white",
    borderRadius: "10px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
    padding: "30px",
    width: "700px",
    gap: "30px",
  },

  left: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },

  image: {
    width: "150px",
    height: "150px",
    borderRadius: "50%",
  },

  right: {
    flex: 1,
  },

  about: {
    marginTop: "10px",
  },

  bookingSection: {
    marginTop: "20px",
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },

  input: {
    padding: "8px",
    borderRadius: "5px",
    border: "1px solid #ccc",
  },

  button: {
    marginTop: "10px",
    padding: "10px",
    backgroundColor: "#2c3e50",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
};
